CREATE OR REPLACE FUNCTION fpa_cnv_method_dividend (as_accno char) RETURNS varchar AS $body$
DECLARE

  ls_acc_no char(50);
  ls_return varchar(3);

BEGIN
  ls_acc_no := trim(both as_accno);
  ls_acc_no := upper(substr(ls_acc_no,1,3));
  --ใช้ิconvert ข้อมูลปันผลจากปีปีที่แล้ว  ของสหกรณ์ออมททรัพย์นาวิกโยธินเท่านั้นั
  if coalesce(ls_acc_no::text, '') = '' then
    ls_return := 'CSH';
  else
    case ls_acc_no
     when 'ACC' then
       ls_return := 'TRD';
     when 'TRA' then
       ls_return := 'SHR';
     else
       ls_return := 'TRB';
   end case;
  end if;

return  ls_return;

exception when others then CALL spa_dberror('FPA_CNV_METHOD_DIVIDEND');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
